function initTable(){const t=document.querySelector("#playerTable tbody");for(let e=0;e<4;e++){const o=document.createElement("tr");o.dataset.party=e;let r=`<td class="party-label">파티원 ${e+1}</td>`;for(let t=0;t<3;t++)r+='<td><input type="number" class="power-input" placeholder="던담딜" min="1"></td>';o.innerHTML=r,t.appendChild(o)}document.querySelectorAll("#playerTable tbody tr").forEach(t=>{t.querySelectorAll("input").forEach(e=>{e.addEventListener("input",()=>updateHighlight(t))})})}function updateHighlight(t){const e=Array.from(t.querySelectorAll("input")),o=e.map(t=>parseFloat(t.value)||0),r=Math.max(...o);e.forEach(t=>{t.classList.toggle("is-ppyok",r>0&&parseFloat(t.value)===r)})}function clearAll(){document.querySelectorAll("#playerTable tbody tr").forEach(t=>{t.querySelectorAll("input").forEach(t=>{t.value="",t.classList.remove("is-ppyok")})}),document.getElementById("output").innerHTML='<p class="pw-hint">조합 버튼을 눌러 최적 파티를 확인하세요</p>'}function fillRandom(){document.querySelectorAll("#playerTable tbody tr").forEach(t=>{const e=t.querySelectorAll("input"),o=Math.floor(3*Math.random());e.forEach((t,e)=>{t.value=e===o?Math.floor(60*Math.random())+520:Math.floor(80*Math.random())+360}),updateHighlight(t)})}function getPermutations(t){if(t.length<=1)return[[...t]];const e=[];for(let o=0;o<t.length;o++){getPermutations(t.filter((t,e)=>e!==o)).forEach(r=>e.push([t[o],...r]))}return e}function findBestCombination(t){const e=t.map((t,e)=>t.map((t,o)=>({power:t,party:e,idx:o})).sort((t,e)=>e.power-t.power)),o=e.map(t=>t[0]),r=e.flatMap(t=>[t[1],t[2]]);let l={minTotal:-1,rows:null};for(const n of getPermutations([0,1,2,3])){if(n.some((t,e)=>t===e))continue;const s=new Array(4);n.forEach((t,e)=>s[t]=e);const p=s.map(t=>o[t].power),i=[[],[],[],[]],c=[2,2,2,2];function a(t){if(t===r.length){const t=i.map((t,e)=>p[e]+t.reduce((t,e)=>t+e.power,0)),e=Math.min(...t);return void(e>l.minTotal&&(l.minTotal=e,l.rows=i.map((e,r)=>({ppyok:o[s[r]],normals:[...e],total:t[r]}))))}const e=r[t];for(let o=0;o<4;o++)o!==e.party&&0!==c[o]&&(c[o]--,i[o].push(e),a(t+1),i[o].pop(),c[o]++)}a(0)}return l}function calculate(){const t=[];let e=!0;if(document.querySelectorAll("#playerTable tbody tr").forEach(o=>{const r=Array.from(o.querySelectorAll("input")).map(t=>parseInt(t.value,10));r.some(t=>isNaN(t)||t<=0)&&(e=!1),t.push(r)}),!e)return void alert("모든 파티원의 딜러 전투력 3개를 입력해주세요.");displayResult(findBestCombination(t))}function displayResult(t){const e=document.getElementById("output");if(!t.rows)return void(e.innerHTML='<p class="text-danger">유효한 조합을 찾을 수 없습니다.</p>');let o='<div class="result-list">';t.rows.forEach((t,e)=>{const r=[t.ppyok,...t.normals].sort((t,e)=>e.power-t.power);o+=`<div class="result-row">\n            <span class="result-idx">${e+1}</span>\n            <div class="result-dealers">`,r.forEach(e=>{const r=e===t.ppyok;o+=`<span class="result-dealer${r?" is-ppyok":""}">\n                ${e.power}<small>[${e.party+1}]${r?"★":""}</small>\n            </span>`}),o+=`</div><span class="result-total">(${t.total})</span></div>`}),o+="</div>",e.innerHTML=o}initTable();